import{_ as e,c as a,o as n,ag as i}from"./chunks/framework.S-Qvb3wi.js";const m=JSON.parse('{"title":"Overview","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),t={name:"guide/index.md"};function l(p,s,r,o,d,h){return n(),a("div",null,s[0]||(s[0]=[i(`<h1 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h1><p>NpgsqlRest is a complete standalone <strong>web server</strong> that runs independently of your PostgreSQL database. It will automatically create HTTP REST endpoints based on:</p><ul><li>Configuration files.</li><li>PostgreSQL database.</li></ul><p>It is built using the latest .NET with the default .NET cross-platform Kestrel web server.</p><p>The entire web server is compiled into native, <strong>ready-to-run executable</strong> without any dependencies.</p><p>It is also free and open-source and different builds for different platforms, directly from source code are also possible.</p><p>What does it mean to configure endpoints from your database?</p><h2 id="postgresql-comments" tabindex="-1">PostgreSQL Comments <a class="header-anchor" href="#postgresql-comments" aria-label="Permalink to &quot;PostgreSQL Comments&quot;">​</a></h2><p>It means you can add <strong>declarative configuration into PostgreSQL object comments</strong>. PostgreSQL supports setting up comments on database objects using <a href="https://www.postgresql.org/docs/current/sql-comment.html" target="_blank" rel="noreferrer"><code>COMMENT ON</code></a> declarations.</p><p>For example:</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">comment on function get_my_data() is </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;HTTP&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Using default configuration, this will generate HTTP REST Endpoint <code>GET api/get-my-data</code>.</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">comment on function admin_function() is </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">HTTP GET /admin_data</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">authorize admin</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>And this will generate <code>GET /admin_data</code> and authorize only <code>admin</code> roles.</p><p>You can change behavior and details of your generated endpoints. For example, HTTP caching:</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">comment on function my_cached_data() is </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">HTTP</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Cache-Control: public, max-age=31536000</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>You can also configure CRUD endpoints on tables. For example, let&#39;s create a read and create endpoints. It looks like this:</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">comment </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">on</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> my_table() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">is</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">for select</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">HTTP GET</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">for insert</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">HTTP PUT</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>Anything that isn&#39;t recognized as a valid comment annotation declaration is simply ignored and treated as a normal comment.</p><p>Note that most of these endpoint settings can be set through configuration files.</p><p>Once your endpoints are configured and HTTP endpoints are exposed in the NpgsqlRest web server, you can use that metadata to generate code for even more rapid development.</p><h2 id="code-generation" tabindex="-1">Code Generation <a class="header-anchor" href="#code-generation" aria-label="Permalink to &quot;Code Generation&quot;">​</a></h2><p>NpgsqlRest implements system of plugins, and</p>`,23)]))}const u=e(t,[["render",l]]);export{m as __pageData,u as default};
